(window.webpackJsonp=window.webpackJsonp||[]).push([[1189],{1115:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\"># Definition for an interval.</span>\\n<span class=\\"hljs-comment\\"># class Interval(object):</span>\\n<span class=\\"hljs-comment\\">#     def __init__(self, s=0, e=0):</span>\\n<span class=\\"hljs-comment\\">#         self.start = s</span>\\n<span class=\\"hljs-comment\\">#         self.end = e</span>\\n\\n<span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">findRightInterval</span><span class=\\"hljs-params\\">(self, intervals)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type intervals: List[Interval]\\n        :rtype: List[int]\\n        \\"\\"\\"</span>\\n        aux=[<span class=\\"hljs-literal\\">None</span>]*len(intervals)\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(len(intervals)):\\n          n=intervals[i]\\n          aux[i]=[n.start,n.end,i]\\n        aux.sort(key=<span class=\\"hljs-keyword\\">lambda</span> x:(x[<span class=\\"hljs-number\\">0</span>]))\\n        <span class=\\"hljs-comment\\"># print aux</span>\\n        ans=[<span class=\\"hljs-literal\\">None</span>]*len(aux)\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(len(aux)):\\n          curID=aux[i][<span class=\\"hljs-number\\">2</span>]\\n          <span class=\\"hljs-keyword\\">if</span> i==len(aux)<span class=\\"hljs-number\\">-1</span>:\\n            ans[curID]=<span class=\\"hljs-number\\">-1</span>\\n          <span class=\\"hljs-keyword\\">else</span>:\\n            lo=i+<span class=\\"hljs-number\\">1</span>\\n            hi=len(aux)<span class=\\"hljs-number\\">-1</span>\\n            target=aux[i][<span class=\\"hljs-number\\">1</span>]\\n            <span class=\\"hljs-keyword\\">while</span> lo&lt;hi:\\n              mid=(lo+hi)//<span class=\\"hljs-number\\">2</span>\\n              <span class=\\"hljs-keyword\\">if</span> aux[mid][<span class=\\"hljs-number\\">0</span>]&lt;target:\\n                lo=mid+<span class=\\"hljs-number\\">1</span>\\n              <span class=\\"hljs-keyword\\">else</span>:\\n                hi=mid\\n            <span class=\\"hljs-comment\\"># print aux,lo,i,target</span>\\n            <span class=\\"hljs-keyword\\">if</span> aux[lo][<span class=\\"hljs-number\\">0</span>]&gt;=target:\\n              ans[curID]=aux[lo][<span class=\\"hljs-number\\">2</span>]\\n            <span class=\\"hljs-keyword\\">else</span>:\\n              ans[curID]=<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">return</span> ans\\n</code></pre>\\n"],"titleSlug":"find-right-interval","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u533a\u95f4\u6570\u7ec4 <code>intervals</code> \uff0c\u5176\u4e2d\xa0<code>intervals[i] = [start<sub>i</sub>, end<sub>i</sub>]</code> \uff0c\u4e14\u6bcf\u4e2a\xa0<code>start<sub>i</sub></code> \u90fd <strong>\u4e0d\u540c</strong> \u3002</p>\\n\\n<p>\u533a\u95f4 <code>i</code> \u7684 <strong>\u53f3\u4fa7\u533a\u95f4</strong> \u53ef\u4ee5\u8bb0\u4f5c\u533a\u95f4 <code>j</code> \uff0c\u5e76\u6ee1\u8db3 <code>start<sub>j</sub></code><code>\xa0>= end<sub>i</sub></code> \uff0c\u4e14 <code>start<sub>j</sub></code> <strong>\u6700\u5c0f\u5316 </strong>\u3002</p>\\n\\n<p>\u8fd4\u56de\u4e00\u4e2a\u7531\u6bcf\u4e2a\u533a\u95f4 <code>i</code> \u7684 <strong>\u53f3\u4fa7\u533a\u95f4</strong> \u7684\u6700\u5c0f\u8d77\u59cb\u4f4d\u7f6e\u7ec4\u6210\u7684\u6570\u7ec4\u3002\u5982\u679c\u67d0\u4e2a\u533a\u95f4 <code>i</code> \u4e0d\u5b58\u5728\u5bf9\u5e94\u7684 <strong>\u53f3\u4fa7\u533a\u95f4</strong> \uff0c\u5219\u4e0b\u6807 <code>i</code> \u5904\u7684\u503c\u8bbe\u4e3a <code>-1</code> \u3002</p>\\n\xa0\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>intervals = [[1,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>[-1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u96c6\u5408\u4e2d\u53ea\u6709\u4e00\u4e2a\u533a\u95f4\uff0c\u6240\u4ee5\u8f93\u51fa-1\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>intervals = [[3,4],[2,3],[1,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>[-1, 0, 1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5bf9\u4e8e [3,4] \uff0c\u6ca1\u6709\u6ee1\u8db3\u6761\u4ef6\u7684\u201c\u53f3\u4fa7\u201d\u533a\u95f4\u3002\\n\u5bf9\u4e8e [2,3] \uff0c\u533a\u95f4[3,4]\u5177\u6709\u6700\u5c0f\u7684\u201c\u53f3\u201d\u8d77\u70b9;\\n\u5bf9\u4e8e [1,2] \uff0c\u533a\u95f4[2,3]\u5177\u6709\u6700\u5c0f\u7684\u201c\u53f3\u201d\u8d77\u70b9\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>intervals = [[1,4],[2,3],[3,4]]\\n<strong>\u8f93\u51fa\uff1a</strong>[-1, 2, -1]\\n<strong>\u89e3\u91ca\uff1a</strong>\u5bf9\u4e8e\u533a\u95f4 [1,4] \u548c [3,4] \uff0c\u6ca1\u6709\u6ee1\u8db3\u6761\u4ef6\u7684\u201c\u53f3\u4fa7\u201d\u533a\u95f4\u3002\\n\u5bf9\u4e8e [2,3] \uff0c\u533a\u95f4 [3,4] \u6709\u6700\u5c0f\u7684\u201c\u53f3\u201d\u8d77\u70b9\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <=\xa0intervals.length <= 2 * 10<sup>4</sup></code></li>\\n\\t<li><code>intervals[i].length == 2</code></li>\\n\\t<li><code>-10<sup>6</sup> <= start<sub>i</sub> <= end<sub>i</sub> <= 10<sup>6</sup></code></li>\\n\\t<li>\u6bcf\u4e2a\u95f4\u9694\u7684\u8d77\u70b9\u90fd <strong>\u4e0d\u76f8\u540c</strong></li>\\n</ul>\\n","title":"436. \u5bfb\u627e\u53f3\u533a\u95f4","relatedTags":["\u4e8c\u5206\u67e5\u627e"],"difficult":"Middle","lang":["python"],"uniqueID":"436"}')}}]);